<template>
  <div>
    <canvas id="party"></canvas>
    <div id="header">Carmona Quiz</div>
    <flow-form
      v-bind:questions="questions"
      v-bind:progressbar="true"
      @submit="onSubmit"
      @complete="onComplete"
      @timer="onTimer"
      v-bind:language="language"
      v-bind:standalone="true"
      v-bind:timer="true"
      ref="flowform"
      v-if="formFound"
    >
      <template v-slot:complete>
        <p>
          <span class="fh2">Bra jobbat!</span>
          <span v-if="!submitted" class="f-section-text">
            Du kan gå tillbaka och ändra dina svar eller klicka på nästa för att
            få ditt resultat :)
          </span>
        </p>
      </template>

      <template v-slot:completeButton>
        <div class="f-submit" v-if="!submitted">
          <button
            class="o-btn-action"
            ref="button"
            type="submit"
            href="#"
            v-on:click.prevent="onSubmit()"
            aria-label="Press to submit"
          >
            <span>Nästa</span>
          </button>
        </div>
        <p class="text-success" v-if="submitted && time">
          Din tid: {{ formattedTime }}
        </p>
        <p class="text-success" v-if="submitted">
          Du fick {{ score }} av {{ total }} rätt.
        </p>
      </template>
    </flow-form>
    <div id="no-form" v-else>
      <div>No form found!</div>
    </div>
  </div>
</template>

<script>
import FlowForm, {
  QuestionModel,
  QuestionType,
  ChoiceOption, //eslint-disable-line
  LanguageModel,
} from "@ditdot-dev/vue-flow-form";
import confetti from "canvas-confetti";

import quiz from "./forms/quiz.json";

export default {
  name: "App",
  components: {
    FlowForm,
  },
  mounted() {
    const urlParams = new URLSearchParams(window.location.search);
    const formId = urlParams.get("formId");
    this.getForm(formId);
  },
  data() {
    return {
      submitted: false,
      completed: false,
      formFound: false,
      score: 0,
      total: 0,
      time: 0,
      formattedTime: "",
      language: new LanguageModel({
        enterKey: "Enter",
        shiftKey: "Shift",
        ok: "OK",
        continue: "Fortsätt",
        skip: "Hoppa över",
        pressEnter: "Tryck :enterKey",
        multipleChoiceHelpText: "Välj flera svar",
        multipleChoiceHelpTextSingle: "Välj ett svar",
        otherPrompt: "Annan",
        placeholder: "Skriv ditt svar här...",
        submitText: "Skicka",
        longTextHelpText: ":shiftKey + :enterKey för att göra ett radbryt.",
        prev: "Föregående",
        next: "Nästa",
        percentCompleted: ":percent% klart",
        invalidPrompt: "Ogiltig inmatning i formuläret",
        thankYouText: "Tack!",
        successText: "Dina svar är inskickde",
        ariaOk: "Tryck för att fortsätta",
        ariaRequired: "Obligatoriskt steg",
        ariaPrev: "Föregående steg",
        ariaNext: "Nästa steg",
        ariaSubmitText: "Tryck för att skicka in",
        ariaMultipleChoice: "Tryck på :letter för att välja",
        ariaTypeAnswer: "Skriv ditt svar här",
      }),
      questions: [],
    };
  },
  methods: {
    onSubmit() {
      this.$refs.flowform.submitted = true;

      this.submitted = true;
      this.calculateScore();
      this.party();
    },
    onTimer(time, formattedTime) {
      this.time = formattedTime;
      this.formattedTime = formattedTime;
    },
    calculateScore() {
      this.questions.forEach((question) => {
        if (question.type !== QuestionType.SectionBreak) {
          let answer = question.answer;
          if (answer === true) {
            this.score++;
          }
        }
      });
    },
    onComplete(completed, questionList) {//eslint-disable-line
      this.completed = completed;
    },
    getForm(formId) {
      let form = quiz[formId];
      this.total = form.questions.length;
      if (form) {
        this.questions.push(
          new QuestionModel({
            title: form.title,
            tagline: this.total + (this.total == 1 ? " fråga" : " frågor"),
            subtitle: form.subtitle,
            description: form.description,
            type: QuestionType.SectionBreak,
            required: true,
          })
        );

        form.questions.forEach((question) => {
          let options = question.options.map((option) => {
            return new ChoiceOption({
              label: option.label,
              value: option.value,
            });
          });

          this.questions.push(
            new QuestionModel({
              title: question.title,
              subtitle: question.subtitle,
              type: QuestionType.MultipleChoice,
              multiple: false,
              required: true,
              options: options,
            })
          );
        });

        this.formFound = true;
      } else {
        this.formFound = false;
      }
    },
    party() {
      var conf = confetti.create(document.getElementById("party"), {
        resize: true,
        useWorker: true,
      });
      // conf({
      //   particleCount: 100,
      //   spread: 70,
      //   origin: { y: 0.6 },
      // });
      var duration = 15 * 1000;
      var animationEnd = Date.now() + duration;
      var defaults = { startVelocity: 30, spread: 360, ticks: 60, zIndex: 0 };

      function randomInRange(min, max) {
        return Math.random() * (max - min) + min;
      }

      var interval = setInterval(function() {
        var timeLeft = animationEnd - Date.now();

        if (timeLeft <= 0) {
          return clearInterval(interval);
        }

        var particleCount = 50 * (timeLeft / duration);
        // since particles fall down, start a bit higher than random
        conf(Object.assign({}, defaults, { particleCount, origin: { x: randomInRange(0.1, 0.3), y: Math.random() - 0.2 } }));
        conf(Object.assign({}, defaults, { particleCount, origin: { x: randomInRange(0.7, 0.9), y: Math.random() - 0.2 } }));
      }, 250);
    },
  },
};
</script>

